{
  "mode": "method",
  "tests": [
    {
      "name": "consistent_dropdown_options",
      "input": {
        "new_options": ["Option A", "Option B", "Option C"],
        "old_options": ["Option A", "Option B", "Option C"]
      },
      "output": true,
      "notes": "Validates that the dropdown options in the new app match those in the old app."
    },
    {
      "name": "dropdown_options_mismatch",
      "input": {
        "new_options": ["Option A", "Option D"],
        "old_options": ["Option A", "Option B", "Option C"]
      },
      "output": false,
      "notes": "Checks for discrepancies in dropdown options between new and old apps."
    },
    {
      "name": "sql_file_update_check",
      "input": {
        "sql_file": "topgear_scorecard.sql",
        "expected_data": ["Data1", "Data2", "Data3"]
      },
      "output": true,
      "notes": "Ensures the SQL file contains the correct data for the Topgear Scorecard Issue."
    },
    {
      "name": "sql_file_data_inconsistency",
      "input": {
        "sql_file": "topgear_scorecard.sql",
        "expected_data": ["Data1", "Data4"]
      },
      "output": false,
      "notes": "Validates that the SQL file does not contain unexpected data."
    },
    {
      "name": "no_unnecessary_changes",
      "input": {
        "file_changes": ["file1.js", "file2.css"],
        "unnecessary_changes": false
      },
      "output": true,
      "notes": "Checks that no unnecessary updates were made to files."
    },
    {
      "name": "functionality_preserved",
      "input": {
        "function_name": "calculateScore",
        "input_data": [10, 20]
      },
      "output": 30,
      "notes": "Ensures that existing functions remain unbroken after updates."
    },
    {
      "name": "edge_case_empty_dropdown",
      "input": {
        "new_options": [],
        "old_options": []
      },
      "output": true,
      "notes": "Tests the scenario where both dropdowns are empty, expecting them to match."
    },
    {
      "name": "edge_case_single_option",
      "input": {
        "new_options": ["Only Option"],
        "old_options": ["Only Option"]
      },
      "output": true,
      "notes": "Validates that a single option in both dropdowns is consistent."
    }
  ],
  "assumptions": "The dropdown options are case-sensitive and must match exactly.",
  "notes": "Ensure to test both the UI and backend functionalities as per the requirements."
}
